// Custom key class must implement both hashCode() and equals()
public class Point {
    int x, y;
    @Override public int hashCode() { return 31 * x + y; }
    @Override public boolean equals(Object o) {
        if (!(o instanceof Point)) return false;
        Point p = (Point) o;
        return x == p.x && y == p.y;
    }
}

