// 4. OBSERVER: event notification
interface EventListener { void onEvent(String event); }

public class EventBus {
    private Map<String, List<EventListener>> listeners = new HashMap<>();

    public void subscribe(String event, EventListener l) {
        listeners.computeIfAbsent(event, k -> new ArrayList<>()).add(l);
    }

    public void publish(String event) {
        listeners.getOrDefault(event, List.of()).forEach(l -> l.onEvent(event));
    }
}

