// 1. Custom annotation definition
@Retention(RetentionPolicy.RUNTIME)  // visible at runtime
@Target({ElementType.METHOD, ElementType.FIELD})  // where it can be applied
public @interface Validate {
    int minLength() default 0;
    boolean required() default true;
    String message() default "Validation failed";
}

// 2. Using the annotation
public class User {
    @Validate(required = true, minLength = 3)
    private String name;

    @Validate(required = false)
    private String nickname;

    @Validate(minLength = 8, message = "Password must be at least 8 chars")
    private String password;
}

// 3. Processing annotations with Reflection
public class Validator {
    public static List<String> validate(Object obj) throws IllegalAccessException {
        List<String> errors = new ArrayList<>();
        Class<?> clazz = obj.getClass();

        for (Field field : clazz.getDeclaredFields()) {
            field.setAccessible(true);  // bypass private access
            Validate ann = field.getAnnotation(Validate.class);
            if (ann == null) continue;

            Object value = field.get(obj);
            if (ann.required() && value == null) {
                errors.add(field.getName() + " is required");
            } else if (value instanceof String s && s.length() < ann.minLength()) {
                errors.add(ann.message() + " (" + field.getName() + ")");
            }
        }
        return errors;
    }
}

