import org.springframework.boot.*;
import org.springframework.boot.autoconfigure.*;
import org.springframework.stereotype.*;
import org.springframework.web.bind.annotation.*;
import org.springframework.beans.factory.annotation.*;
import org.springframework.data.jpa.repository.*;

// 1. Entry point
@SpringBootApplication  // = @Configuration + @ComponentScan + @EnableAutoConfiguration
public class Application {
    public static void main(String[] args) {
        SpringApplication.run(Application.class, args);
    }
}

// 2. Repository layer (data access)
@Repository
public interface UserRepository extends JpaRepository<User, Long> {
    Optional<User> findByEmail(String email);  // Spring Data generates SQL
    List<User> findByDepartmentAndSalaryGreaterThan(String dept, double salary);
}

// 3. Service layer (business logic)
@Service
public class UserService {
    private final UserRepository userRepo;  // constructor injection (preferred)

    @Autowired  // optional when only one constructor
    public UserService(UserRepository userRepo) {
        this.userRepo = userRepo;
    }

    public User createUser(String name, String email) {
        if (userRepo.findByEmail(email).isPresent()) {
            throw new IllegalArgumentException("Email already exists");
        }
        return userRepo.save(new User(name, email));
    }
}

// 4. REST Controller (web layer)
@RestController  // = @Controller + @ResponseBody
@RequestMapping("/api/users")
public class UserController {
    private final UserService userService;

    public UserController(UserService userService) {
        this.userService = userService;
    }

    @GetMapping("/{id}")
    public ResponseEntity<User> getUser(@PathVariable Long id) {
        return userService.findById(id)
            .map(ResponseEntity::ok)
            .orElse(ResponseEntity.notFound().build());
    }

    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    public User createUser(@RequestBody @Valid CreateUserRequest req) {
        return userService.createUser(req.getName(), req.getEmail());
    }
}

// 5. Configuration
@Configuration
public class AppConfig {
    @Bean  // Spring manages this object's lifecycle
    public ObjectMapper objectMapper() {
        return new ObjectMapper().findAndRegisterModules();
    }
